    /// <param name="format"></param>
    public static ulong EstimateContentCapacity(ulong fileSize, string format)
    {
        ArgumentNullException.ThrowIfNull(format);
        var result = NativeMethods.EstimateContentCapacity(
            fileSize,
            format
        );
        if (result == IntPtr.Zero) { var err = GetLastError(); if (err.Code != 0) throw err; }
        var returnValue = result;
        return returnValue;
    }

