        );
        if (result == IntPtr.Zero) { var err = GetLastError(); if (err.Code != 0) throw err; }
        var jsonPtr = NativeMethods.EmailExtractionResultToJson(result);
        var json = Marshal.PtrToStringUTF8(jsonPtr);
        NativeMethods.FreeString(jsonPtr);
        NativeMethods.EmailExtractionResultFree(result);
        var returnValue = JsonSerializer.Deserialize<EmailExtractionResult>(json ?? "null", JsonOptions)!;
        return returnValue;
    }

